const rows = $input.all();
const today = new Date();

function addBusinessDays(date, days) {
  const holidays = ['2026/01/01','2026/01/12','2026/02/11','2026/02/23','2026/03/20','2026/04/29','2026/05/03','2026/05/04','2026/05/05','2026/07/20','2026/08/11','2026/09/21','2026/09/22','2026/09/23','2026/10/12','2026/11/03','2026/11/23'];
  let count = 0;
  let current = new Date(date);
  while (count < days) {
    current.setDate(current.getDate() + 1);
    const d = current.getDay();
    const ds = current.toLocaleDateString('ja-JP').replace(/[年月]/g,'/');
    if (d !== 0 && d !== 6 && !holidays.includes(ds)) count++;
  }
  return current;
}

function isSameDay(a, b) {
  return a.getFullYear()===b.getFullYear() && a.getMonth()===b.getMonth() && a.getDate()===b.getDate();
}

const reminder1 = []; // Day8
const reminder2 = []; // Day12（キャンセルポリシー）

rows.forEach(item => {
  const row = item.json;
  const callDate = row['後確日'] ? new Date(row['後確日']) : null;
  const status = row['ステータス'];
  if (!callDate || !['未定','FP未連絡'].includes(status)) return;

  const day8 = addBusinessDays(callDate, 4);
  const day12 = addBusinessDays(callDate, 8);

  if (isSameDay(day8, today)) reminder1.push(row);
  if (isSameDay(day12, today)) reminder2.push(row);
});

return [
  ...reminder1.map(r => ({ json: { ...r, reminderType: 'reminder1' }})),
  ...reminder2.map(r => ({ json: { ...r, reminderType: 'reminder2' }}))
];
